func entryBadgeClass(color string) string {
	base := "inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-medium "
	switch color {
	case "green", "success":
		return base + "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400"
	case "red", "danger":
		return base + "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400"
	case "yellow", "warning":
		return base + "bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400"
	case "blue", "info":
		return base + "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400"
	default:
		return base + "bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300"
	}
}

func entryWeightClass(weight string) string {
	switch weight {
	case "bold":
		return "font-bold"
	case "semibold":
		return "font-semibold"
	case "medium":
		return "font-medium"
	default:
		return ""
	}
}

func entryIconColor(color string) string {
	switch color {
	case "green", "success":
		return "text-green-600 dark:text-green-400"
	case "red", "danger":
		return "text-red-600 dark:text-red-400"
	case "yellow", "warning":
		return "text-yellow-600 dark:text-yellow-400"
	case "blue", "info":
		return "text-blue-600 dark:text-blue-400"
	case "purple":
		return "text-purple-600 dark:text-purple-400"
	case "primary":
		return "text-primary-600 dark:text-primary-400"
	default:
		return "text-gray-500 dark:text-gray-400"
	}
}

